import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京美食推荐","description":"","frontmatter":{},"headers":[],"relativePath":"guide/food.md","filePath":"guide/food.md","lastUpdated":1784712887000}'),r={name:"guide/food.md"};function d(n,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="北京美食推荐" tabindex="-1">北京美食推荐 <a class="header-anchor" href="#北京美食推荐" aria-label="Permalink to &quot;北京美食推荐&quot;">​</a></h1><blockquote><p>&quot;民以食为天，食以味为先。&quot;</p></blockquote><h2 id="北京特色美食" tabindex="-1">北京特色美食 <a class="header-anchor" href="#北京特色美食" aria-label="Permalink to &quot;北京特色美食&quot;">​</a></h2><h3 id="🦆-北京烤鸭-——-必吃no-1" tabindex="-1">🦆 北京烤鸭 —— 必吃NO.1 <a class="header-anchor" href="#🦆-北京烤鸭-——-必吃no-1" aria-label="Permalink to &quot;🦆 北京烤鸭 —— 必吃NO.1&quot;">​</a></h3><p>北京烤鸭是北京最著名的美食，被誉为&quot;天下美味&quot;。</p><h4 id="推荐餐厅" tabindex="-1">推荐餐厅 <a class="header-anchor" href="#推荐餐厅" aria-label="Permalink to &quot;推荐餐厅&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">餐厅</th><th style="text-align:left;">特色</th><th style="text-align:center;">价格</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全聚德</strong></td><td style="text-align:left;">老字号，挂炉烤鸭</td><td style="text-align:center;">300-500元</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>便宜坊</strong></td><td style="text-align:left;">老字号，焖炉烤鸭</td><td style="text-align:center;">200-400元</td><td style="text-align:left;">崇文门外大街</td></tr><tr><td style="text-align:left;"><strong>大董</strong></td><td style="text-align:left;">创新烤鸭，高端</td><td style="text-align:center;">400-800元</td><td style="text-align:left;">王府井</td></tr><tr><td style="text-align:left;"><strong>四季民福</strong></td><td style="text-align:left;">性价比高</td><td style="text-align:center;">200-300元</td><td style="text-align:left;">故宫店</td></tr></tbody></table><h4 id="正确吃法" tabindex="-1">正确吃法 <a class="header-anchor" href="#正确吃法" aria-label="Permalink to &quot;正确吃法&quot;">​</a></h4><ol><li>荷叶饼摊开</li><li>抹甜面酱</li><li>放葱丝、黄瓜条</li><li>放鸭皮、鸭肉</li><li>卷起来，一口咬下</li></ol><hr><h3 id="🥟-北京小吃" tabindex="-1">🥟 北京小吃 <a class="header-anchor" href="#🥟-北京小吃" aria-label="Permalink to &quot;🥟 北京小吃&quot;">​</a></h3><h4 id="豆汁焦圈" tabindex="-1">豆汁焦圈 <a class="header-anchor" href="#豆汁焦圈" aria-label="Permalink to &quot;豆汁焦圈&quot;">​</a></h4><ul><li>豆汁：绿豆发酵而成，酸中带香</li><li>推荐：护国寺小吃店</li><li>价格：5-10元</li></ul><h4 id="炸酱面" tabindex="-1">炸酱面 <a class="header-anchor" href="#炸酱面" aria-label="Permalink to &quot;炸酱面&quot;">​</a></h4><ul><li>老北京人的家常面食</li><li>推荐：海碗居、老北京炸酱面大王</li><li>价格：20-40元</li></ul><h4 id="卤煮火烧" tabindex="-1">卤煮火烧 <a class="header-anchor" href="#卤煮火烧" aria-label="Permalink to &quot;卤煮火烧&quot;">​</a></h4><ul><li>猪下水加火烧炖煮</li><li>推荐：小肠陈、北新桥卤煮</li><li>价格：25-40元</li></ul><h4 id="炒肝" tabindex="-1">炒肝 <a class="header-anchor" href="#炒肝" aria-label="Permalink to &quot;炒肝&quot;">​</a></h4><ul><li>以猪肝和大肠为主料</li><li>推荐：姚记炒肝、天兴居</li><li>价格：15-30元</li></ul><h4 id="爆肚" tabindex="-1">爆肚 <a class="header-anchor" href="#爆肚" aria-label="Permalink to &quot;爆肚&quot;">​</a></h4><ul><li>牛羊肚快速汆烫</li><li>推荐：爆肚冯、东兴顺爆肚张</li><li>价格：50-100元</li></ul><h4 id="传统糕点" tabindex="-1">传统糕点 <a class="header-anchor" href="#传统糕点" aria-label="Permalink to &quot;传统糕点&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">糕点</th><th style="text-align:left;">特点</th><th style="text-align:center;">价格</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>艾窝窝</strong></td><td style="text-align:left;">糯米制，馅心多样</td><td style="text-align:center;">2-5元</td></tr><tr><td style="text-align:left;"><strong>驴打滚</strong></td><td style="text-align:left;">黄豆面裹糯米</td><td style="text-align:center;">2-5元</td></tr><tr><td style="text-align:left;"><strong>豌豆黄</strong></td><td style="text-align:left;">入口即化</td><td style="text-align:center;">2-5元</td></tr><tr><td style="text-align:left;"><strong>糖耳朵</strong></td><td style="text-align:left;">蜜麻花，甜脆</td><td style="text-align:center;">2-5元</td></tr></tbody></table><h4 id="推荐店铺" tabindex="-1">推荐店铺 <a class="header-anchor" href="#推荐店铺" aria-label="Permalink to &quot;推荐店铺&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">店铺</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>护国寺小吃</strong></td><td style="text-align:left;">北京小吃大全</td><td style="text-align:left;">护国寺大街</td></tr><tr><td style="text-align:left;"><strong>锦芳小吃</strong></td><td style="text-align:left;">回民小吃</td><td style="text-align:left;">磁器口</td></tr><tr><td style="text-align:left;"><strong>白记年糕</strong></td><td style="text-align:left;">牛街名店</td><td style="text-align:left;">牛街</td></tr><tr><td style="text-align:left;"><strong>稻香村</strong></td><td style="text-align:left;">糕点礼盒</td><td style="text-align:left;">多家门店</td></tr></tbody></table><hr><h3 id="🍖-京味菜肴" tabindex="-1">🍖 京味菜肴 <a class="header-anchor" href="#🍖-京味菜肴" aria-label="Permalink to &quot;🍖 京味菜肴&quot;">​</a></h3><h4 id="涮羊肉" tabindex="-1">涮羊肉 <a class="header-anchor" href="#涮羊肉" aria-label="Permalink to &quot;涮羊肉&quot;">​</a></h4><ul><li>北方传统火锅</li><li>推荐：东来顺、南门涮肉</li><li>价格：100-150元/人</li></ul><h4 id="羊蝎子" tabindex="-1">羊蝎子 <a class="header-anchor" href="#羊蝎子" aria-label="Permalink to &quot;羊蝎子&quot;">​</a></h4><ul><li>羊脊骨火锅</li><li>价格：80-120元/人</li></ul><h4 id="京酱肉丝" tabindex="-1">京酱肉丝 <a class="header-anchor" href="#京酱肉丝" aria-label="Permalink to &quot;京酱肉丝&quot;">​</a></h4><ul><li>北京名菜，甜面酱炒制肉丝</li><li>价格：40-60元</li></ul><hr><h2 id="美食街区" tabindex="-1">美食街区 <a class="header-anchor" href="#美食街区" aria-label="Permalink to &quot;美食街区&quot;">​</a></h2><h3 id="王府井小吃街" tabindex="-1">王府井小吃街 <a class="header-anchor" href="#王府井小吃街" aria-label="Permalink to &quot;王府井小吃街&quot;">​</a></h3><ul><li>游客聚集，小吃种类繁多</li><li>注意：价格偏高</li></ul><h3 id="南锣鼓巷" tabindex="-1">南锣鼓巷 <a class="header-anchor" href="#南锣鼓巷" aria-label="Permalink to &quot;南锣鼓巷&quot;">​</a></h3><ul><li>文艺范，新老结合</li><li>推荐：文宇奶酪、海小姐玫瑰饼</li></ul><h3 id="簋街" tabindex="-1">簋街 <a class="header-anchor" href="#簋街" aria-label="Permalink to &quot;簋街&quot;">​</a></h3><ul><li>夜宵圣地，小龙虾、烧烤</li><li>时间：晚上6点后最热闹</li></ul><h3 id="牛街" tabindex="-1">牛街 <a class="header-anchor" href="#牛街" aria-label="Permalink to &quot;牛街&quot;">​</a></h3><ul><li>回民美食，正宗地道</li><li>推荐：聚宝源涮肉、白记年糕</li></ul><hr><h2 id="餐厅推荐" tabindex="-1">餐厅推荐 <a class="header-anchor" href="#餐厅推荐" aria-label="Permalink to &quot;餐厅推荐&quot;">​</a></h2><h3 id="高端宴请" tabindex="-1">高端宴请 <a class="header-anchor" href="#高端宴请" aria-label="Permalink to &quot;高端宴请&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">餐厅</th><th style="text-align:left;">菜系</th><th style="text-align:center;">人均</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大董</strong></td><td style="text-align:left;">创意中餐</td><td style="text-align:center;">500+</td><td style="text-align:left;">烤鸭、意境菜</td></tr><tr><td style="text-align:left;"><strong>花家怡园</strong></td><td style="text-align:left;">京菜</td><td style="text-align:center;">300+</td><td style="text-align:left;">四合院环境</td></tr></tbody></table><h3 id="中端消费" tabindex="-1">中端消费 <a class="header-anchor" href="#中端消费" aria-label="Permalink to &quot;中端消费&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">餐厅</th><th style="text-align:left;">菜系</th><th style="text-align:center;">人均</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大鸭梨</strong></td><td style="text-align:left;">京菜</td><td style="text-align:center;">100</td></tr><tr><td style="text-align:left;"><strong>郭林家常菜</strong></td><td style="text-align:left;">京菜</td><td style="text-align:center;">80</td></tr><tr><td style="text-align:left;"><strong>眉州东坡</strong></td><td style="text-align:left;">川菜</td><td style="text-align:center;">100</td></tr><tr><td style="text-align:left;"><strong>西贝莜面村</strong></td><td style="text-align:left;">西北菜</td><td style="text-align:center;">100</td></tr></tbody></table><h3 id="平民消费" tabindex="-1">平民消费 <a class="header-anchor" href="#平民消费" aria-label="Permalink to &quot;平民消费&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">餐厅</th><th style="text-align:left;">特色</th><th style="text-align:center;">人均</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>护国寺小吃</strong></td><td style="text-align:left;">北京小吃</td><td style="text-align:center;">30</td></tr><tr><td style="text-align:left;"><strong>庆丰包子铺</strong></td><td style="text-align:left;">包子</td><td style="text-align:center;">30</td></tr></tbody></table><hr><h2 id="用餐时间" tabindex="-1">用餐时间 <a class="header-anchor" href="#用餐时间" aria-label="Permalink to &quot;用餐时间&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">餐次</th><th style="text-align:left;">时间</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>早餐</strong></td><td style="text-align:left;">6:00-9:00</td></tr><tr><td style="text-align:center;"><strong>午餐</strong></td><td style="text-align:left;">11:00-14:00</td></tr><tr><td style="text-align:center;"><strong>晚餐</strong></td><td style="text-align:left;">17:00-21:00</td></tr><tr><td style="text-align:center;"><strong>夜宵</strong></td><td style="text-align:left;">21:00-凌晨</td></tr></tbody></table><hr><h2 id="避坑指南" tabindex="-1">避坑指南 <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;避坑指南&quot;">​</a></h2><ul><li>❌ 景区周边小吃街谨慎消费</li><li>❌ 不要轻信拉客</li><li>❌ 点餐前问清价格</li><li>✅ 去当地人多的店</li><li>✅ 看大众点评评分</li></ul><hr><p><strong>💡 Tips</strong>：烤鸭一定要提前预订，尤其是旺季！</p>',59)])])}const y=e(r,[["render",d]]);export{f as __pageData,y as default};
